#!/bin/sh
set -eu

# Use a real PNG logo for auth/app logo. Do not wrap the PNG inside SVG.

cat > /app/client/dist/assets/logo.png.b64 <<'EOF'

EOF
base64 -d /app/client/dist/assets/logo.png.b64 > /app/client/dist/assets/logo.png
cp /app/client/dist/assets/logo.png /app/client/public/assets/logo.png 2>/dev/null || true
rm -f /app/client/dist/assets/logo.png.b64

find /app/client/dist -type f \( -name '*.js' -o -name '*.css' -o -name '*.html' -o -name '*.json' \) -print0 \
  | xargs -0 sed -i \
      -e 's|assets/logo.svg|assets/logo.png|g' \
      -e 's|/assets/logo.svg|/assets/logo.png|g'
EOF
